{
  "name": "MiamRecipes - Votre Carnet de Cuisine",
  "description": "Une application de partage de recettes moderne et minimaliste utilisant Supabase pour le stockage des données et des images.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type Category = 'Entrée' | 'Plat' | 'Dessert';

export interface Recipe {
  id: string;
  title: string;
  category: Category;
  ingredients: string[];
  instructions: string[];
  image_url: string;
  created_at: string;
}

export interface RecipeFormData {
  title: string;
  category: Category;
  ingredients: string[];
  instructions: string[];
  image?: File;
}

import { createClient } from '@supabase/supabase-js';

// IMPORTANT: Remplacer par vos propres clés Supabase
// Ces valeurs devraient idéalement être dans des variables d'environnement.
const supabaseUrl = 'https://your-project-url.supabase.co';
const supabaseAnonKey = 'your-anon-key';

export const supabase = createClient(supabaseUrl, supabaseAnonKey);

/**
 * INSTRUCTIONS SQL POUR SUPABASE :
 * 
 * -- Table des recettes
 * CREATE TABLE recipes (
 *   id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
 *   title TEXT NOT NULL,
 *   category TEXT NOT NULL CHECK (category IN ('Entrée', 'Plat', 'Dessert')),
 *   ingredients TEXT[] NOT NULL,
 *   instructions TEXT[] NOT NULL,
 *   image_url TEXT,
 *   created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL
 * );
 * 
 * -- Bucket de stockage
 * -- Créez un bucket public nommé 'recipe-images' dans Supabase Storage.
 */

import React from 'react';
import { HashRouter, Routes, Route } from 'react-router-dom';
import Home from './views/Home';
import RecipeDetailView from './views/RecipeDetailView';
import AddRecipeView from './views/AddRecipeView';
import Navbar from './components/Navbar';

const App: React.FC = () => {
  return (
    <HashRouter>
      <div className="min-h-screen flex flex-col bg-gray-50 text-gray-900">
        <Navbar />
        <main className="flex-grow container mx-auto px-4 py-8 max-w-4xl">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/recipe/:id" element={<RecipeDetailView />} />
            <Route path="/add" element={<AddRecipeView />} />
          </Routes>
        </main>
        <footer className="py-6 text-center text-gray-500 text-sm border-t border-gray-200 bg-white">
          &copy; {new Date().getFullYear()} MiamRecipes - Fait avec passion.
        </footer>
      </div>
    </HashRouter>
  );
};

export default App;

import React from 'react';
import { Link } from 'react-router-dom';

const Navbar: React.FC = () => {
  return (
    <nav className="sticky top-0 z-50 bg-white shadow-sm border-b border-gray-100">
      <div className="container mx-auto px-4 h-16 flex items-center justify-between max-w-4xl">
        <Link to="/" className="flex items-center space-x-2">
          <span className="text-2xl">🥘</span>
          <span className="font-bold text-xl tracking-tight text-orange-600">MiamRecipes</span>
        </Link>
        <Link 
          to="/add" 
          className="bg-orange-500 hover:bg-orange-600 text-white px-4 py-2 rounded-full text-sm font-medium transition-colors shadow-md shadow-orange-100 flex items-center"
        >
          <i className="fas fa-plus mr-2"></i>
          Ajouter
        </Link>
      </div>
    </nav>
  );
};

export default Navbar;

import React from 'react';
import { Link } from 'react-router-dom';
import { Recipe } from '../types';

interface RecipeCardProps {
  recipe: Recipe;
}

const RecipeCard: React.FC<RecipeCardProps> = ({ recipe }) => {
  const placeholderImage = `https://picsum.photos/seed/${recipe.id}/400/300`;

  return (
    <Link 
      to={`/recipe/${recipe.id}`}
      className="group bg-white rounded-2xl overflow-hidden shadow-sm hover:shadow-xl transition-all duration-300 border border-gray-100 flex flex-col h-full"
    >
      <div className="relative h-48 overflow-hidden">
        <img 
          src={recipe.image_url || placeholderImage} 
          alt={recipe.title} 
          className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
        />
        <div className="absolute top-3 left-3">
          <span className={`
            px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider text-white shadow-sm
            ${recipe.category === 'Entrée' ? 'bg-green-500' : ''}
            ${recipe.category === 'Plat' ? 'bg-orange-500' : ''}
            ${recipe.category === 'Dessert' ? 'bg-pink-500' : ''}
          `}>
            {recipe.category}
          </span>
        </div>
      </div>
      <div className="p-4 flex-grow flex flex-col justify-between">
        <h3 className="font-bold text-lg text-gray-800 line-clamp-1 group-hover:text-orange-600 transition-colors">
          {recipe.title}
        </h3>
        <div className="flex items-center mt-3 text-gray-500 text-xs">
          <span className="flex items-center">
            <i className="fas fa-carrot mr-1"></i>
            {recipe.ingredients.length} ingrédients
          </span>
          <span className="mx-2">•</span>
          <span className="flex items-center">
            <i className="fas fa-clock mr-1"></i>
            {new Date(recipe.created_at).toLocaleDateString('fr-FR')}
          </span>
        </div>
      </div>
    </Link>
  );
};

export default RecipeCard;

import React, { useState, useEffect } from 'react';
import { supabase } from '../supabaseClient';
import { Recipe, Category } from '../types';
import RecipeCard from '../components/RecipeCard';

const Home: React.FC = () => {
  const [recipes, setRecipes] = useState<Recipe[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [activeCategory, setActiveCategory] = useState<Category | 'Tous'>('Tous');

  useEffect(() => {
    fetchRecipes();
  }, []);

  const fetchRecipes = async () => {
    try {
      setLoading(true);
      const { data, error } = await supabase
        .from('recipes')
        .select('*')
        .order('created_at', { ascending: false });

      if (error) throw error;
      setRecipes(data || []);
    } catch (error) {
      console.error('Erreur lors du chargement des recettes:', error);
    } finally {
      setLoading(false);
    }
  };

  const filteredRecipes = recipes.filter(r => {
    const matchesSearch = r.title.toLowerCase().includes(search.toLowerCase());
    const matchesCategory = activeCategory === 'Tous' || r.category === activeCategory;
    return matchesSearch && matchesCategory;
  });

  const categories: (Category | 'Tous')[] = ['Tous', 'Entrée', 'Plat', 'Dessert'];

  return (
    <div className="space-y-8 animate-fadeIn">
      <header className="text-center space-y-4">
        <h1 className="text-4xl font-extrabold text-gray-900 tracking-tight">
          Qu'est-ce qu'on <span className="text-orange-500">mange</span> aujourd'hui ?
        </h1>
        <p className="text-gray-500 max-w-md mx-auto">
          Découvrez et partagez vos meilleures recettes de famille. Simple, rapide et délicieux.
        </p>
      </header>

      {/* Barre de recherche et filtres */}
      <div className="space-y-4">
        <div className="relative max-w-xl mx-auto">
          <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-gray-400"></i>
          <input 
            type="text" 
            placeholder="Rechercher une recette..." 
            className="w-full pl-12 pr-4 py-3 rounded-2xl bg-white border border-gray-200 focus:outline-none focus:ring-2 focus:ring-orange-500 focus:border-transparent transition-all shadow-sm"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>

        <div className="flex justify-center flex-wrap gap-2">
          {categories.map(cat => (
            <button
              key={cat}
              onClick={() => setActiveCategory(cat)}
              className={`
                px-6 py-2 rounded-full text-sm font-semibold transition-all
                ${activeCategory === cat 
                  ? 'bg-orange-500 text-white shadow-lg shadow-orange-100' 
                  : 'bg-white text-gray-500 hover:bg-gray-100 border border-gray-100'}
              `}
            >
              {cat}
            </button>
          ))}
        </div>
      </div>

      {/* Grille de recettes */}
      {loading ? (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
          {[1, 2, 3].map(i => (
            <div key={i} className="h-64 bg-gray-200 rounded-2xl animate-pulse"></div>
          ))}
        </div>
      ) : filteredRecipes.length > 0 ? (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredRecipes.map(recipe => (
            <RecipeCard key={recipe.id} recipe={recipe} />
          ))}
        </div>
      ) : (
        <div className="text-center py-20 bg-white rounded-3xl border border-dashed border-gray-200">
          <div className="text-5xl mb-4">🍳</div>
          <h3 className="text-xl font-bold text-gray-800">Aucune recette trouvée</h3>
          <p className="text-gray-500">Essayez de modifier votre recherche ou ajoutez une nouvelle pépite !</p>
        </div>
      )}
    </div>
  );
};

export default Home;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { supabase } from '../supabaseClient';
import { Recipe } from '../types';

const RecipeDetailView: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [recipe, setRecipe] = useState<Recipe | null>(null);
  const [loading, setLoading] = useState(true);
  const [checkedIngredients, setCheckedIngredients] = useState<Record<number, boolean>>({});

  useEffect(() => {
    if (id) fetchRecipe(id);
  }, [id]);

  const fetchRecipe = async (recipeId: string) => {
    try {
      setLoading(true);
      const { data, error } = await supabase
        .from('recipes')
        .select('*')
        .eq('id', recipeId)
        .single();

      if (error) throw error;
      setRecipe(data);
    } catch (error) {
      console.error('Erreur:', error);
      navigate('/');
    } finally {
      setLoading(false);
    }
  };

  const toggleIngredient = (index: number) => {
    setCheckedIngredients(prev => ({
      ...prev,
      [index]: !prev[index]
    }));
  };

  if (loading) return <div className="animate-pulse flex flex-col items-center justify-center h-64"><div className="w-12 h-12 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div></div>;
  if (!recipe) return <div className="text-center text-gray-500">Recette introuvable.</div>;

  return (
    <div className="bg-white rounded-3xl overflow-hidden shadow-xl shadow-gray-100 border border-gray-100 animate-slideUp">
      <div className="relative h-64 sm:h-96">
        <img 
          src={recipe.image_url || `https://picsum.photos/seed/${recipe.id}/800/600`} 
          alt={recipe.title} 
          className="w-full h-full object-cover"
        />
        <button 
          onClick={() => navigate(-1)}
          className="absolute top-4 left-4 w-10 h-10 bg-white/80 backdrop-blur-md rounded-full flex items-center justify-center hover:bg-white transition-colors shadow-lg"
        >
          <i className="fas fa-arrow-left text-gray-800"></i>
        </button>
      </div>

      <div className="p-6 sm:p-10 space-y-8">
        <header className="space-y-2">
          <div className="flex items-center space-x-2">
            <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider text-white ${recipe.category === 'Entrée' ? 'bg-green-500' : recipe.category === 'Plat' ? 'bg-orange-500' : 'bg-pink-500'}`}>
              {recipe.category}
            </span>
            <span className="text-gray-400 text-xs">{new Date(recipe.created_at).toLocaleDateString('fr-FR')}</span>
          </div>
          <h1 className="text-3xl sm:text-4xl font-black text-gray-900 leading-tight">
            {recipe.title}
          </h1>
        </header>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-10">
          {/* Ingrédients */}
          <section className="md:col-span-1 space-y-4">
            <h2 className="text-xl font-bold flex items-center text-gray-800">
              <i className="fas fa-list-ul mr-3 text-orange-500"></i>
              Ingrédients
            </h2>
            <div className="bg-orange-50 rounded-2xl p-4 space-y-3">
              {recipe.ingredients.map((item, idx) => (
                <div 
                  key={idx} 
                  className="flex items-start group cursor-pointer" 
                  onClick={() => toggleIngredient(idx)}
                >
                  <div className={`
                    w-5 h-5 rounded-md border flex-shrink-0 mt-0.5 flex items-center justify-center transition-all
                    ${checkedIngredients[idx] ? 'bg-orange-500 border-orange-500' : 'bg-white border-gray-300 group-hover:border-orange-400'}
                  `}>
                    {checkedIngredients[idx] && <i className="fas fa-check text-[10px] text-white"></i>}
                  </div>
                  <span className={`ml-3 text-sm transition-all ${checkedIngredients[idx] ? 'line-through text-gray-400' : 'text-gray-700 font-medium'}`}>
                    {item}
                  </span>
                </div>
              ))}
            </div>
          </section>

          {/* Instructions */}
          <section className="md:col-span-2 space-y-4">
            <h2 className="text-xl font-bold flex items-center text-gray-800">
              <i className="fas fa-utensils mr-3 text-orange-500"></i>
              Préparation
            </h2>
            <div className="space-y-6">
              {recipe.instructions.map((step, idx) => (
                <div key={idx} className="flex space-x-4">
                  <span className="flex-shrink-0 w-8 h-8 rounded-full bg-orange-100 text-orange-600 font-bold flex items-center justify-center text-sm">
                    {idx + 1}
                  </span>
                  <p className="text-gray-700 leading-relaxed pt-1">
                    {step}
                  </p>
                </div>
              ))}
            </div>
          </section>
        </div>
      </div>
    </div>
  );
};

export default RecipeDetailView;

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { supabase } from '../supabaseClient';
import { Category } from '../types';

const AddRecipeView: React.FC = () => {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [title, setTitle] = useState('');
  const [category, setCategory] = useState<Category>('Plat');
  const [ingredients, setIngredients] = useState<string[]>(['']);
  const [instructions, setInstructions] = useState<string[]>(['']);
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [imagePreview, setImagePreview] = useState<string | null>(null);

  const handleAddField = (setter: React.Dispatch<React.SetStateAction<string[]>>) => {
    setter(prev => [...prev, '']);
  };

  const handleFieldChange = (
    index: number, 
    value: string, 
    setter: React.Dispatch<React.SetStateAction<string[]>>
  ) => {
    setter(prev => {
      const copy = [...prev];
      copy[index] = value;
      return copy;
    });
  };

  const handleRemoveField = (
    index: number, 
    setter: React.Dispatch<React.SetStateAction<string[]>>, 
    list: string[]
  ) => {
    if (list.length > 1) {
      setter(prev => prev.filter((_, i) => i !== index));
    }
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setImageFile(file);
      const reader = new FileReader();
      reader.onloadend = () => {
        setImagePreview(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (loading) return;

    try {
      setLoading(true);

      let imageUrl = '';

      // 1. Upload Image to Storage if exists
      if (imageFile) {
        const fileExt = imageFile.name.split('.').pop();
        const fileName = `${Math.random().toString(36).substring(2)}.${fileExt}`;
        const filePath = `recipes/${fileName}`;

        const { error: uploadError } = await supabase.storage
          .from('recipe-images')
          .upload(filePath, imageFile);

        if (uploadError) throw uploadError;

        const { data: publicUrlData } = supabase.storage
          .from('recipe-images')
          .getPublicUrl(filePath);

        imageUrl = publicUrlData.publicUrl;
      }

      // 2. Insert into DB
      const { error: insertError } = await supabase
        .from('recipes')
        .insert([{
          title,
          category,
          ingredients: ingredients.filter(i => i.trim() !== ''),
          instructions: instructions.filter(i => i.trim() !== ''),
          image_url: imageUrl
        }]);

      if (insertError) throw insertError;

      alert('Recette ajoutée avec succès !');
      navigate('/');
    } catch (error) {
      console.error('Erreur:', error);
      alert('Une erreur est survenue lors de l\'ajout de la recette.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-white rounded-3xl shadow-xl shadow-gray-100 border border-gray-100 max-w-2xl mx-auto overflow-hidden animate-slideUp">
      <div className="bg-orange-500 p-8 text-white">
        <h1 className="text-3xl font-black">Ajouter une pépite</h1>
        <p className="opacity-90">Partagez votre secret culinaire avec la communauté.</p>
      </div>

      <form onSubmit={handleSubmit} className="p-8 space-y-8">
        {/* Section Titre & Catégorie */}
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="block text-sm font-bold text-gray-700 uppercase tracking-wide">Nom de la recette</label>
            <input 
              type="text" 
              required
              placeholder="Ex: Tarte Tatin de Mamie"
              className="w-full px-4 py-3 rounded-xl bg-gray-50 border border-gray-200 focus:ring-2 focus:ring-orange-500 outline-none transition-all"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
            />
          </div>
          <div className="space-y-2">
            <label className="block text-sm font-bold text-gray-700 uppercase tracking-wide">Catégorie</label>
            <select 
              className="w-full px-4 py-3 rounded-xl bg-gray-50 border border-gray-200 focus:ring-2 focus:ring-orange-500 outline-none transition-all appearance-none"
              value={category}
              onChange={(e) => setCategory(e.target.value as Category)}
            >
              <option value="Entrée">Entrée</option>
              <option value="Plat">Plat</option>
              <option value="Dessert">Dessert</option>
            </select>
          </div>
        </div>

        {/* Upload Image */}
        <div className="space-y-2">
          <label className="block text-sm font-bold text-gray-700 uppercase tracking-wide">Photo du plat</label>
          <div 
            className={`
              relative h-48 rounded-2xl border-2 border-dashed border-gray-200 flex flex-col items-center justify-center overflow-hidden transition-all
              ${imagePreview ? 'border-orange-500' : 'hover:border-orange-300'}
            `}
          >
            {imagePreview ? (
              <>
                <img src={imagePreview} alt="Preview" className="w-full h-full object-cover" />
                <button 
                  type="button"
                  onClick={() => { setImageFile(null); setImagePreview(null); }}
                  className="absolute top-2 right-2 bg-red-500 text-white w-8 h-8 rounded-full flex items-center justify-center shadow-lg"
                >
                  <i className="fas fa-times"></i>
                </button>
              </>
            ) : (
              <div className="text-center p-4">
                <i className="fas fa-camera text-3xl text-gray-300 mb-2"></i>
                <p className="text-sm text-gray-500 font-medium">Cliquez pour ajouter une image</p>
                <input 
                  type="file" 
                  accept="image/*"
                  className="absolute inset-0 opacity-0 cursor-pointer"
                  onChange={handleImageChange}
                />
              </div>
            )}
          </div>
        </div>

        {/* Liste des Ingrédients */}
        <div className="space-y-4">
          <label className="block text-sm font-bold text-gray-700 uppercase tracking-wide flex justify-between items-center">
            Ingrédients
            <button 
              type="button" 
              onClick={() => handleAddField(setIngredients)}
              className="text-orange-500 hover:text-orange-600 text-xs font-bold"
            >
              + Ajouter
            </button>
          </label>
          <div className="space-y-3">
            {ingredients.map((ing, idx) => (
              <div key={idx} className="flex space-x-2">
                <input 
                  type="text" 
                  placeholder={`Ingrédient ${idx + 1}`}
                  className="flex-grow px-4 py-2 rounded-xl bg-gray-50 border border-gray-200 focus:ring-1 focus:ring-orange-500 outline-none"
                  value={ing}
                  onChange={(e) => handleFieldChange(idx, e.target.value, setIngredients)}
                />
                {ingredients.length > 1 && (
                  <button 
                    type="button"
                    onClick={() => handleRemoveField(idx, setIngredients, ingredients)}
                    className="text-gray-300 hover:text-red-500 transition-colors"
                  >
                    <i className="fas fa-trash-alt"></i>
                  </button>
                )}
              </div>
            ))}
          </div>
        </div>

        {/* Étapes de préparation */}
        <div className="space-y-4">
          <label className="block text-sm font-bold text-gray-700 uppercase tracking-wide flex justify-between items-center">
            Préparation (étapes)
            <button 
              type="button" 
              onClick={() => handleAddField(setInstructions)}
              className="text-orange-500 hover:text-orange-600 text-xs font-bold"
            >
              + Ajouter
            </button>
          </label>
          <div className="space-y-3">
            {instructions.map((step, idx) => (
              <div key={idx} className="flex space-x-2">
                <textarea 
                  placeholder={`Étape ${idx + 1}`}
                  className="flex-grow px-4 py-2 rounded-xl bg-gray-50 border border-gray-200 focus:ring-1 focus:ring-orange-500 outline-none h-20 resize-none"
                  value={step}
                  onChange={(e) => handleFieldChange(idx, e.target.value, setInstructions)}
                />
                {instructions.length > 1 && (
                  <button 
                    type="button"
                    onClick={() => handleRemoveField(idx, setInstructions, instructions)}
                    className="text-gray-300 hover:text-red-500 transition-colors"
                  >
                    <i className="fas fa-trash-alt"></i>
                  </button>
                )}
              </div>
            ))}
          </div>
        </div>

        {/* Bouton de validation */}
        <button 
          type="submit" 
          disabled={loading}
          className={`
            w-full py-4 rounded-2xl font-black text-lg shadow-xl shadow-orange-100 transition-all transform
            ${loading ? 'bg-gray-400 cursor-not-allowed' : 'bg-orange-500 hover:bg-orange-600 text-white hover:-translate-y-1 active:scale-95'}
          `}
        >
          {loading ? (
            <span className="flex items-center justify-center">
              <i className="fas fa-spinner fa-spin mr-3"></i>
              Publication...
            </span>
          ) : 'Publier ma recette'}
        </button>
      </form>
    </div>
  );
};

export default AddRecipeView;

import { createClient } from '@supabase/supabase-js';

// Tente de récupérer les clés depuis process.env ou utilise les placeholders
// REMPLACER ces valeurs par vos vraies clés du tableau de bord Supabase (Settings > API)
const supabaseUrl = (process.env.SUPABASE_URL && process.env.SUPABASE_URL !== 'undefined') 
  ? process.env.SUPABASE_URL 
  : 'https://votre-projet.supabase.co';

const supabaseAnonKey = (process.env.SUPABASE_ANON_KEY && process.env.SUPABASE_ANON_KEY !== 'undefined') 
  ? process.env.SUPABASE_ANON_KEY 
  : 'votre-cle-anon-ici';

export const supabase = createClient(supabaseUrl, supabaseAnonKey);

