/**
 * RAPPEL SQL (À exécuter dans l'éditeur SQL de Supabase) :
 * 
 * -- 1. Créer la table
 * CREATE TABLE recipes (
 *   id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
 *   title TEXT NOT NULL,
 *   category TEXT NOT NULL CHECK (category IN ('Entrée', 'Plat', 'Dessert')),
 *   ingredients TEXT[] NOT NULL,
 *   instructions TEXT[] NOT NULL,
 *   image_url TEXT,
 *   created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL
 * );
 * 
 * -- 2. Activer RLS (Row Level Security) - Optionnel pour les tests
 * ALTER TABLE recipes ENABLE ROW LEVEL SECURITY;
 * CREATE POLICY "Allow public access" ON recipes FOR ALL USING (true);
 * 
 * -- 3. Créer le bucket de stockage
 * -- Allez dans 'Storage', créez un bucket 'recipe-images', réglez-le sur "Public".
 * -- Ajoutez une policy Storage pour autoriser l'upload public si nécessaire.
 */

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { supabase } from '../supabaseClient';
import { Category } from '../types';

const AddRecipeView: React.FC = () => {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [title, setTitle] = useState('');
  const [category, setCategory] = useState<Category>('Plat');
  const [ingredients, setIngredients] = useState<string[]>(['']);
  const [instructions, setInstructions] = useState<string[]>(['']);
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [imagePreview, setImagePreview] = useState<string | null>(null);

  const handleAddField = (setter: React.Dispatch<React.SetStateAction<string[]>>) => {
    setter(prev => [...prev, '']);
  };

  const handleFieldChange = (
    index: number, 
    value: string, 
    setter: React.Dispatch<React.SetStateAction<string[]>>
  ) => {
    setter(prev => {
      const copy = [...prev];
      copy[index] = value;
      return copy;
    });
  };

  const handleRemoveField = (
    index: number, 
    setter: React.Dispatch<React.SetStateAction<string[]>>, 
    list: string[]
  ) => {
    if (list.length > 1) {
      setter(prev => prev.filter((_, i) => i !== index));
    }
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setImageFile(file);
      const reader = new FileReader();
      reader.onloadend = () => {
        setImagePreview(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (loading) return;

    // Validation basique
    if (!title.trim()) {
      alert("Veuillez donner un titre à votre recette.");
      return;
    }

    const filteredIngredients = ingredients.filter(i => i.trim() !== '');
    const filteredInstructions = instructions.filter(i => i.trim() !== '');

    if (filteredIngredients.length === 0 || filteredInstructions.length === 0) {
      alert("Veuillez ajouter au moins un ingrédient et une étape.");
      return;
    }

    try {
      setLoading(true);

      let imageUrl = '';

      // 1. Upload Image to Storage if exists
      if (imageFile) {
        const fileExt = imageFile.name.split('.').pop();
        const fileName = `${Date.now()}-${Math.random().toString(36).substring(2)}.${fileExt}`;
        const filePath = `${fileName}`; // Upload à la racine du bucket

        const { error: uploadError, data: uploadData } = await supabase.storage
          .from('recipe-images')
          .upload(filePath, imageFile);

        if (uploadError) {
          console.error('Erreur Storage:', uploadError);
          throw new Error(`Erreur lors de l'upload de l'image: ${uploadError.message}`);
        }

        const { data: publicUrlData } = supabase.storage
          .from('recipe-images')
          .getPublicUrl(filePath);

        imageUrl = publicUrlData.publicUrl;
      }

      // 2. Insert into DB
      const { error: insertError, data } = await supabase
        .from('recipes')
        .insert([{
          title: title.trim(),
          category,
          ingredients: filteredIngredients,
          instructions: filteredInstructions,
          image_url: imageUrl
        }])
        .select();

      if (insertError) {
        console.error('Erreur Database:', insertError);
        throw new Error(`Erreur lors de l'enregistrement en base: ${insertError.message}`);
      }

      console.log('Recette enregistrée:', data);
      alert('Recette ajoutée avec succès !');
      navigate('/');
    } catch (error: any) {
      console.error('Détail de l\'erreur:', error);
      alert(error.message || "Une erreur inattendue est survenue.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-white rounded-3xl shadow-xl shadow-gray-100 border border-gray-100 max-w-2xl mx-auto overflow-hidden animate-slideUp">
      <div className="bg-orange-500 p-8 text-white">
        <h1 className="text-3xl font-black">Ajouter une pépite</h1>
        <p className="opacity-90">Partagez votre secret culinaire avec la communauté.</p>
      </div>

      <form onSubmit={handleSubmit} className="p-8 space-y-8">
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="block text-sm font-bold text-gray-700 uppercase tracking-wide">Nom de la recette</label>
            <input 
              type="text" 
              required
              placeholder="Ex: Tarte Tatin de Mamie"
              className="w-full px-4 py-3 rounded-xl bg-gray-50 border border-gray-200 focus:ring-2 focus:ring-orange-500 outline-none transition-all"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
            />
          </div>
          <div className="space-y-2">
            <label className="block text-sm font-bold text-gray-700 uppercase tracking-wide">Catégorie</label>
            <select 
              className="w-full px-4 py-3 rounded-xl bg-gray-50 border border-gray-200 focus:ring-2 focus:ring-orange-500 outline-none transition-all appearance-none"
              value={category}
              onChange={(e) => setCategory(e.target.value as Category)}
            >
              <option value="Entrée">Entrée</option>
              <option value="Plat">Plat</option>
              <option value="Dessert">Dessert</option>
            </select>
          </div>
        </div>

        <div className="space-y-2">
          <label className="block text-sm font-bold text-gray-700 uppercase tracking-wide">Photo du plat</label>
          <div 
            className={`
              relative h-48 rounded-2xl border-2 border-dashed border-gray-200 flex flex-col items-center justify-center overflow-hidden transition-all
              ${imagePreview ? 'border-orange-500' : 'hover:border-orange-300'}
            `}
          >
            {imagePreview ? (
              <>
                <img src={imagePreview} alt="Preview" className="w-full h-full object-cover" />
                <button 
                  type="button"
                  onClick={() => { setImageFile(null); setImagePreview(null); }}
                  className="absolute top-2 right-2 bg-red-500 text-white w-8 h-8 rounded-full flex items-center justify-center shadow-lg"
                >
                  <i className="fas fa-times"></i>
                </button>
              </>
            ) : (
              <div className="text-center p-4">
                <i className="fas fa-camera text-3xl text-gray-300 mb-2"></i>
                <p className="text-sm text-gray-500 font-medium">Cliquez pour ajouter une image</p>
                <input 
                  type="file" 
                  accept="image/*"
                  className="absolute inset-0 opacity-0 cursor-pointer"
                  onChange={handleImageChange}
                />
              </div>
            )}
          </div>
        </div>

        <div className="space-y-4">
          <label className="block text-sm font-bold text-gray-700 uppercase tracking-wide flex justify-between items-center">
            Ingrédients
            <button 
              type="button" 
              onClick={() => handleAddField(setIngredients)}
              className="text-orange-500 hover:text-orange-600 text-xs font-bold"
            >
              + Ajouter
            </button>
          </label>
          <div className="space-y-3">
            {ingredients.map((ing, idx) => (
              <div key={idx} className="flex space-x-2">
                <input 
                  type="text" 
                  placeholder={`Ingrédient ${idx + 1}`}
                  className="flex-grow px-4 py-2 rounded-xl bg-gray-50 border border-gray-200 focus:ring-1 focus:ring-orange-500 outline-none"
                  value={ing}
                  onChange={(e) => handleFieldChange(idx, e.target.value, setIngredients)}
                />
                {ingredients.length > 1 && (
                  <button 
                    type="button"
                    onClick={() => handleRemoveField(idx, setIngredients, ingredients)}
                    className="text-gray-300 hover:text-red-500 transition-colors"
                  >
                    <i className="fas fa-trash-alt"></i>
                  </button>
                )}
              </div>
            ))}
          </div>
        </div>

        <div className="space-y-4">
          <label className="block text-sm font-bold text-gray-700 uppercase tracking-wide flex justify-between items-center">
            Préparation (étapes)
            <button 
              type="button" 
              onClick={() => handleAddField(setInstructions)}
              className="text-orange-500 hover:text-orange-600 text-xs font-bold"
            >
              + Ajouter
            </button>
          </label>
          <div className="space-y-3">
            {instructions.map((step, idx) => (
              <div key={idx} className="flex space-x-2">
                <textarea 
                  placeholder={`Étape ${idx + 1}`}
                  className="flex-grow px-4 py-2 rounded-xl bg-gray-50 border border-gray-200 focus:ring-1 focus:ring-orange-500 outline-none h-20 resize-none"
                  value={step}
                  onChange={(e) => handleFieldChange(idx, e.target.value, setInstructions)}
                />
                {instructions.length > 1 && (
                  <button 
                    type="button"
                    onClick={() => handleRemoveField(idx, setInstructions, instructions)}
                    className="text-gray-300 hover:text-red-500 transition-colors"
                  >
                    <i className="fas fa-trash-alt"></i>
                  </button>
                )}
              </div>
            ))}
          </div>
        </div>

        <button 
          type="submit" 
          disabled={loading}
          className={`
            w-full py-4 rounded-2xl font-black text-lg shadow-xl shadow-orange-100 transition-all transform
            ${loading ? 'bg-gray-400 cursor-not-allowed' : 'bg-orange-500 hover:bg-orange-600 text-white hover:-translate-y-1 active:scale-95'}
          `}
        >
          {loading ? (
            <span className="flex items-center justify-center">
              <i className="fas fa-spinner fa-spin mr-3"></i>
              Publication...
            </span>
          ) : 'Publier ma recette'}
        </button>
      </form>
    </div>
  );
};

