import React, { useState, useEffect } from 'react';
import { supabase } from '../supabaseClient';
import { Recipe, Category } from '../types';
import RecipeCard from '../components/RecipeCard';

const Home: React.FC = () => {
  const [recipes, setRecipes] = useState<Recipe[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [search, setSearch] = useState('');
  const [activeCategory, setActiveCategory] = useState<Category | 'Tous'>('Tous');

  useEffect(() => {
    fetchRecipes();
  }, []);

  const fetchRecipes = async () => {
    try {
      setLoading(true);
      setError(null);
      const { data, error: supabaseError } = await supabase
        .from('recipes')
        .select('*')
        .order('created_at', { ascending: false });

      if (supabaseError) throw supabaseError;
      setRecipes(data || []);
    } catch (err: any) {
      console.error('Erreur chargement:', err);
      setError(err.message || "Erreur de connexion à la base de données.");
    } finally {
      setLoading(false);
    }
  };

  const filteredRecipes = recipes.filter(r => {
    const matchesSearch = r.title.toLowerCase().includes(search.toLowerCase());
    const matchesCategory = activeCategory === 'Tous' || r.category === activeCategory;
    return matchesSearch && matchesCategory;
  });

  return (
    <div className="space-y-8 animate-fadeIn">
      <header className="text-center space-y-4">
        <h1 className="text-4xl font-extrabold text-gray-900 tracking-tight">
          Qu'est-ce qu'on <span className="text-orange-500">mange</span> aujourd'hui ?
        </h1>
      </header>

      <div className="space-y-4">
        <div className="relative max-w-xl mx-auto">
          <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-gray-400"></i>
          <input 
            type="text" 
            placeholder="Rechercher une recette..." 
            className="w-full pl-12 pr-4 py-3 rounded-2xl bg-white border border-gray-200 outline-none shadow-sm focus:ring-2 focus:ring-orange-500"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>

        <div className="flex justify-center flex-wrap gap-2">
          {['Tous', 'Entrée', 'Plat', 'Dessert'].map(cat => (
            <button
              key={cat}
              onClick={() => setActiveCategory(cat as any)}
              className={`px-6 py-2 rounded-full text-sm font-semibold transition-all ${activeCategory === cat ? 'bg-orange-500 text-white shadow-lg' : 'bg-white text-gray-500 border border-gray-100'}`}
            >
              {cat}
            </button>
          ))}
        </div>
      </div>

      {error ? (
        <div className="p-6 bg-red-50 border border-red-100 rounded-3xl text-center">
          <p className="text-red-600 font-bold">Erreur : {error}</p>
          <p className="text-red-400 text-sm mt-2">Vérifiez que la table 'recipes' existe et que les droits (RLS) sont activés.</p>
          <button onClick={fetchRecipes} className="mt-4 px-4 py-2 bg-red-600 text-white rounded-lg text-sm">Réessayer</button>
        </div>
      ) : loading ? (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
          {[1, 2, 3].map(i => <div key={i} className="h-64 bg-gray-100 rounded-2xl animate-pulse"></div>)}
        </div>
      ) : filteredRecipes.length > 0 ? (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredRecipes.map(recipe => <RecipeCard key={recipe.id} recipe={recipe} />)}
        </div>
      ) : (
        <div className="text-center py-20 bg-white rounded-3xl border border-dashed border-gray-200">
          <div className="text-5xl mb-4">🍳</div>
          <h3 className="text-xl font-bold text-gray-800">Aucune recette</h3>
          <p className="text-gray-500">Ajoutez votre première recette !</p>
        </div>
      )}
    </div>
  );
};

