import React, { useState, useEffect } from 'react';
import { supabase } from '../supabaseClient';
import { Category } from '../types';

const CategoryManager: React.FC = () => {
  const [categories, setCategories] = useState<Category[]>([]);
  const [loading, setLoading] = useState(true);
  const [newName, setNewName] = useState('');
  const [newColor, setNewColor] = useState('#f97316');

  useEffect(() => {
    fetchCategories();
  }, []);

  const fetchCategories = async () => {
    setLoading(true);
    const { data } = await supabase.from('categories').select('*').order('name');
    if (data) setCategories(data);
    setLoading(false);
  };

  const handleAdd = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newName.trim()) return;
    const { error } = await supabase.from('categories').insert({ name: newName.trim(), color: newColor });
    if (error) alert(error.message);
    else {
      setNewName('');
      fetchCategories();
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm("Supprimer cette catégorie ? Les recettes associées resteront mais n'auront plus de couleur personnalisée.")) return;
    await supabase.from('categories').delete().eq('id', id);
    fetchCategories();
  };

  return (
    <div className="max-w-xl mx-auto space-y-8 animate-fadeIn">
      <div className="bg-white rounded-3xl p-8 shadow-xl border border-gray-100">
        <h1 className="text-2xl font-black mb-6 flex items-center">
          <i className="fas fa-tags mr-3 text-orange-500"></i>
          Gérer les catégories
        </h1>

        <form onSubmit={handleAdd} className="flex gap-2 mb-8">
          <input 
            type="text" placeholder="Nom (Ex: Brunch)" required
            className="flex-grow px-4 py-2 rounded-xl bg-gray-50 border border-gray-200 outline-none focus:ring-2 focus:ring-orange-500"
            value={newName} onChange={e => setNewName(e.target.value)}
          />
          <input 
            type="color" className="w-12 h-10 p-1 bg-white border border-gray-200 rounded-xl cursor-pointer"
            value={newColor} onChange={e => setNewColor(e.target.value)}
          />
          <button type="submit" className="bg-orange-500 text-white px-4 rounded-xl font-bold">Ajouter</button>
        </form>

        <div className="space-y-3">
          {loading ? <div className="animate-pulse h-20 bg-gray-100 rounded-xl"></div> : categories.map(cat => (
            <div key={cat.id} className="flex items-center justify-between p-3 rounded-xl bg-gray-50 border border-gray-100">
              <div className="flex items-center space-x-3">
                <div className="w-6 h-6 rounded-full" style={{ backgroundColor: cat.color }}></div>
                <span className="font-bold text-gray-700">{cat.name}</span>
              </div>
              <button onClick={() => handleDelete(cat.id)} className="text-gray-300 hover:text-red-500">
                <i className="fas fa-trash"></i>
              </button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default CategoryManager;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { supabase } from '../supabaseClient';
import { Recipe, Category } from '../types';

const RecipeDetailView: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [recipe, setRecipe] = useState<Recipe | null>(null);
  const [categoryInfo, setCategoryInfo] = useState<Category | null>(null);
  const [loading, setLoading] = useState(true);
  const [checkedIngredients, setCheckedIngredients] = useState<Record<number, boolean>>({});

  useEffect(() => {
    if (id) fetchRecipe(id);
  }, [id]);

  const fetchRecipe = async (recipeId: string) => {
    try {
      setLoading(true);
      const { data, error } = await supabase.from('recipes').select('*').eq('id', recipeId).single();
      if (error) throw error;
      setRecipe(data);

      // Fetch color info
      const { data: catData } = await supabase.from('categories').select('*').eq('name', data.category).single();
      if (catData) setCategoryInfo(catData);
    } catch (error) {
      navigate('/');
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async () => {
    if (!confirm("Voulez-vous vraiment supprimer cette recette ?")) return;
    const { error } = await supabase.from('recipes').delete().eq('id', id);
    if (!error) navigate('/');
    else alert("Erreur lors de la suppression");
  };

  const exportJPG = async () => {
    if (!recipe) return;

    // Dimensions A4 à 96 DPI
    const width = 794; 
    const height = 1123;
    const canvas = document.createElement('canvas');
    canvas.width = width;
    canvas.height = height;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Fond blanc
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, width, height);

    // 1. Bandeau (2cm ≈ 75px)
    const bandHeight = 75;
    ctx.fillStyle = categoryInfo?.color || '#f97316';
    ctx.fillRect(0, 0, width, bandHeight);

    ctx.fillStyle = '#ffffff';
    ctx.font = 'bold 32px Inter, sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText(recipe.title.toUpperCase(), width / 2, bandHeight / 2 + 10);

    // 2. Photo (5cm ≈ 190px de haut)
    let nextY = bandHeight + 40;
    if (recipe.image_url) {
      const img = new Image();
      img.crossOrigin = "anonymous";
      img.src = recipe.image_url;
      await new Promise(resolve => img.onload = resolve);

      const displayHeight = 190;
      const ratio = img.width / img.height;
      const displayWidth = displayHeight * ratio;
      const xPos = (width - displayWidth) / 2;

      // Bordure 2px
      ctx.fillStyle = '#000000';
      ctx.fillRect(xPos - 2, nextY - 2, displayWidth + 4, displayHeight + 4);
      ctx.drawImage(img, xPos, nextY, displayWidth, displayHeight);
      nextY += displayHeight + 50;
    }

    // 3. Contenu Colonnes 1/4 - 3/4
    const col1X = 50;
    const col1Width = (width - 100) * 0.25;
    const col2X = col1X + col1Width + 40;
    const col2Width = (width - 100) * 0.75 - 40;

    // Ingrédients
    ctx.textAlign = 'left';
    ctx.fillStyle = '#333333';
    ctx.font = 'bold 18px Inter, sans-serif';
    ctx.fillText('INGRÉDIENTS', col1X, nextY);

    ctx.font = '14px Inter, sans-serif';
    let ingY = nextY + 30;
    recipe.ingredients.forEach(ing => {
      ctx.fillText('• ' + ing, col1X, ingY, col1Width);
      ingY += 20;
    });

    // Instructions
    ctx.font = 'bold 18px Inter, sans-serif';
    ctx.fillText('PRÉPARATION', col2X, nextY);

    ctx.font = '14px Inter, sans-serif';
    let stepY = nextY + 30;
    recipe.instructions.forEach((step, idx) => {
      const text = `Etape ${idx + 1} : ${step}`;
      // Basic line wrapping
      const words = text.split(' ');
      let line = '';
      words.forEach(word => {
        let testLine = line + word + ' ';
        if (ctx.measureText(testLine).width > col2Width) {
          ctx.fillText(line, col2X, stepY);
          line = word + ' ';
          stepY += 20;
        } else {
          line = testLine;
        }
      });
      ctx.fillText(line, col2X, stepY);
      stepY += 35;
    });

    // Download
    const dataUrl = canvas.toDataURL('image/jpeg', 0.9);
    const link = document.createElement('a');
    link.download = `Recette-${recipe.title}.jpg`;
    link.href = dataUrl;
    link.click();
  };

  if (loading) return <div className="h-64 flex items-center justify-center"><div className="w-12 h-12 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div></div>;
  if (!recipe) return null;

  const categoryColor = categoryInfo?.color || '#f97316';

  return (
    <div className="bg-white rounded-3xl overflow-hidden shadow-xl border border-gray-100 animate-slideUp">
      <div className="relative h-64 sm:h-80">
        <img src={recipe.image_url || `https://picsum.photos/seed/${recipe.id}/800/600`} className="w-full h-full object-cover" />
        <div className="absolute top-4 left-4 flex space-x-2">
          <button onClick={() => navigate(-1)} className="w-10 h-10 bg-white/90 rounded-full flex items-center justify-center shadow-lg"><i className="fas fa-arrow-left"></i></button>
        </div>
        <div className="absolute top-4 right-4 flex space-x-2">
          <button onClick={exportJPG} title="Exporter JPG" className="w-10 h-10 bg-blue-500 text-white rounded-full flex items-center justify-center shadow-lg hover:bg-blue-600"><i className="fas fa-file-image"></i></button>
          <Link to={`/recipe/edit/${recipe.id}`} className="w-10 h-10 bg-orange-500 text-white rounded-full flex items-center justify-center shadow-lg hover:bg-orange-600"><i className="fas fa-edit"></i></Link>
          <button onClick={handleDelete} className="w-10 h-10 bg-red-500 text-white rounded-full flex items-center justify-center shadow-lg hover:bg-red-600"><i className="fas fa-trash"></i></button>
        </div>
      </div>

      <div className="p-8 space-y-8">
        <header className="space-y-2 text-center">
          <span className="px-4 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest text-white shadow-sm" style={{ backgroundColor: categoryColor }}>
            {recipe.category}
          </span>
          <h1 className="text-4xl font-black text-gray-900">{recipe.title}</h1>
        </header>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
          <aside className="space-y-4">
            <h2 className="font-black text-lg border-b-2 pb-2" style={{ borderColor: categoryColor }}>INGRÉDIENTS</h2>
            <ul className="space-y-2">
              {recipe.ingredients.map((ing, i) => (
                <li key={i} className="flex items-center space-x-2 text-gray-700 font-medium">
                  <div className="w-2 h-2 rounded-full" style={{ backgroundColor: categoryColor }}></div>
                  <span>{ing}</span>
                </li>
              ))}
            </ul>
          </aside>

          <section className="md:col-span-2 space-y-4">
            <h2 className="font-black text-lg border-b-2 pb-2" style={{ borderColor: categoryColor }}>PRÉPARATION</h2>
            <div className="space-y-6">
              {recipe.instructions.map((step, i) => (
                <div key={i} className="flex space-x-4">
                  <span className="flex-shrink-0 w-8 h-8 rounded-lg flex items-center justify-center text-white font-bold text-sm" style={{ backgroundColor: categoryColor }}>{i + 1}</span>
                  <p className="text-gray-700 leading-relaxed pt-1">{step}</p>
                </div>
              ))}
            </div>
          </section>
        </div>
      </div>
    </div>
  );
};

export default RecipeDetailView;

import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { supabase } from '../supabaseClient';
import { Category } from '../types';

const EditRecipeView: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [categories, setCategories] = useState<Category[]>([]);

  const [title, setTitle] = useState('');
  const [category, setCategory] = useState('');
  const [ingredients, setIngredients] = useState<string[]>(['']);
  const [instructions, setInstructions] = useState<string[]>(['']);
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [imagePreview, setImagePreview] = useState<string | null>(null);
  const [existingImageUrl, setExistingImageUrl] = useState('');

  useEffect(() => {
    fetchCategories();
    if (id) fetchRecipe();
  }, [id]);

  const fetchCategories = async () => {
    const { data } = await supabase.from('categories').select('*');
    if (data) setCategories(data);
  };

  const fetchRecipe = async () => {
    const { data } = await supabase.from('recipes').select('*').eq('id', id).single();
    if (data) {
      setTitle(data.title);
      setCategory(data.category);
      setIngredients(data.ingredients);
      setInstructions(data.instructions);
      setExistingImageUrl(data.image_url);
      setImagePreview(data.image_url);
    }
  };

  const handleFieldChange = (idx: number, val: string, setter: React.Dispatch<React.SetStateAction<string[]>>) => {
    setter(prev => {
      const copy = [...prev];
      copy[idx] = val;
      return copy;
    });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    try {
      let imageUrl = existingImageUrl;

      if (imageFile) {
        const fileName = `${Date.now()}-${imageFile.name}`;
        await supabase.storage.from('recipe-images').upload(fileName, imageFile);
        const { data } = supabase.storage.from('recipe-images').getPublicUrl(fileName);
        imageUrl = data.publicUrl;
      }

      await supabase.from('recipes').update({
        title,
        category,
        ingredients: ingredients.filter(i => i.trim()),
        instructions: instructions.filter(i => i.trim()),
        image_url: imageUrl
      }).eq('id', id);

      navigate(`/recipe/${id}`);
    } catch (err) {
      alert("Erreur");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-white rounded-3xl shadow-xl p-8 animate-fadeIn">
      <h1 className="text-3xl font-black mb-8 text-orange-500">Modifier la recette</h1>
      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="grid grid-cols-2 gap-4">
          <input value={title} onChange={e => setTitle(e.target.value)} placeholder="Titre" className="p-3 bg-gray-50 rounded-xl border" required />
          <select value={category} onChange={e => setCategory(e.target.value)} className="p-3 bg-gray-50 rounded-xl border">
            {categories.map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
          </select>
        </div>

        <div className="border-2 border-dashed p-4 rounded-xl text-center">
          {imagePreview && <img src={imagePreview} className="h-40 mx-auto rounded-lg mb-2 object-cover" />}
          <input type="file" onChange={e => {
            const f = e.target.files?.[0];
            if (f) {
              setImageFile(f);
              setImagePreview(URL.createObjectURL(f));
            }
          }} />
        </div>

        <div className="space-y-2">
          <label className="font-bold">Ingrédients</label>
          {ingredients.map((ing, i) => (
            <input key={i} value={ing} onChange={e => handleFieldChange(i, e.target.value, setIngredients)} className="w-full p-2 bg-gray-50 rounded-lg border mb-2" />
          ))}
          <button type="button" onClick={() => setIngredients([...ingredients, ''])} className="text-orange-500 font-bold text-sm">+ Ajouter</button>
        </div>

        <div className="space-y-2">
          <label className="font-bold">Instructions</label>
          {instructions.map((step, i) => (
            <textarea key={i} value={step} onChange={e => handleFieldChange(i, e.target.value, setInstructions)} className="w-full p-2 bg-gray-50 rounded-lg border h-20 mb-2" />
          ))}
          <button type="button" onClick={() => setInstructions([...instructions, ''])} className="text-orange-500 font-bold text-sm">+ Ajouter</button>
        </div>

        <button type="submit" disabled={loading} className="w-full py-4 bg-orange-500 text-white font-black rounded-2xl">
          {loading ? 'Enregistrement...' : 'Mettre à jour'}
        </button>
      </form>
    </div>
  );
};

export default EditRecipeView;

import React, { useState, useEffect } from 'react';
import { supabase } from '../supabaseClient';
import { Recipe, Category } from '../types';
import RecipeCard from '../components/RecipeCard';

const Home: React.FC = () => {
  const [recipes, setRecipes] = useState<Recipe[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [activeCategory, setActiveCategory] = useState('Tous');

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    setLoading(true);
    const [resRecipes, resCats] = await Promise.all([
      supabase.from('recipes').select('*').order('created_at', { ascending: false }),
      supabase.from('categories').select('*').order('name')
    ]);
    if (resRecipes.data) setRecipes(resRecipes.data);
    if (resCats.data) setCategories(resCats.data);
    setLoading(false);
  };

  const filteredRecipes = recipes.filter(r => {
    const matchesSearch = r.title.toLowerCase().includes(search.toLowerCase());
    const matchesCategory = activeCategory === 'Tous' || r.category === activeCategory;
    return matchesSearch && matchesCategory;
  });

  return (
    <div className="space-y-8 animate-fadeIn">
      <header className="text-center space-y-4">
        <h1 className="text-4xl font-black text-gray-900 tracking-tight">
          Qu'est-ce qu'on <span className="text-orange-500">mange</span> ?
        </h1>
      </header>

      <div className="space-y-4">
        <div className="relative max-w-xl mx-auto">
          <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-gray-400"></i>
          <input 
            type="text" placeholder="Rechercher..." 
            className="w-full pl-12 pr-4 py-3 rounded-2xl bg-white border outline-none focus:ring-2 focus:ring-orange-500 shadow-sm"
            value={search} onChange={e => setSearch(e.target.value)}
          />
        </div>

        <div className="flex justify-center flex-wrap gap-2">
          <button
            onClick={() => setActiveCategory('Tous')}
            className={`px-6 py-2 rounded-full text-sm font-bold transition-all ${activeCategory === 'Tous' ? 'bg-orange-500 text-white shadow-lg' : 'bg-white text-gray-400 border border-gray-100'}`}
          >
            Tous
          </button>
          {categories.map(cat => (
            <button
              key={cat.id}
              onClick={() => setActiveCategory(cat.name)}
              className={`px-6 py-2 rounded-full text-sm font-bold transition-all border`}
              style={{ 
                backgroundColor: activeCategory === cat.name ? cat.color : '#ffffff',
                color: activeCategory === cat.name ? '#ffffff' : '#9ca3af',
                borderColor: activeCategory === cat.name ? cat.color : '#f3f4f6'
              }}
            >
              {cat.name}
            </button>
          ))}
        </div>
      </div>

      {loading ? (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
          {[1, 2, 3].map(i => <div key={i} className="h-64 bg-gray-100 rounded-2xl animate-pulse"></div>)}
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredRecipes.map(recipe => <RecipeCard key={recipe.id} recipe={recipe} />)}
        </div>
      )}
    </div>
  );
};

export default Home;

