import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { supabase } from '../supabaseClient';

const AddRecipeView: React.FC = () => {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [title, setTitle] = useState('');
  // Use string for the category name instead of the Category interface to match the Recipe definition
  const [category, setCategory] = useState<string>('Plat');
  const [ingredients, setIngredients] = useState<string[]>(['']);
  const [instructions, setInstructions] = useState<string[]>(['']);
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [imagePreview, setImagePreview] = useState<string | null>(null);

  const handleAddField = (setter: React.Dispatch<React.SetStateAction<string[]>>) => {
    setter(prev => [...prev, '']);
  };

  const handleFieldChange = (index: number, value: string, setter: React.Dispatch<React.SetStateAction<string[]>>) => {
    setter(prev => {
      const copy = [...prev];
      copy[index] = value;
      return copy;
    });
  };

  const handleRemoveField = (index: number, setter: React.Dispatch<React.SetStateAction<string[]>>, list: string[]) => {
    if (list.length > 1) {
      setter(prev => prev.filter((_, i) => i !== index));
    }
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setImageFile(file);
      const reader = new FileReader();
      reader.onloadend = () => setImagePreview(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (loading) return;

    const filteredIngredients = ingredients.filter(i => i.trim() !== '');
    const filteredInstructions = instructions.filter(i => i.trim() !== '');

    if (!title.trim() || filteredIngredients.length === 0 || filteredInstructions.length === 0) {
      alert("Veuillez remplir tous les champs obligatoires.");
      return;
    }

    try {
      setLoading(true);
      let imageUrl = '';

      // 1. Gestion de l'image
      if (imageFile) {
        const fileExt = imageFile.name.split('.').pop();
        const fileName = `${Date.now()}-${Math.random().toString(36).substring(2)}.${fileExt}`;

        const { error: uploadError } = await supabase.storage
          .from('recipe-images')
          .upload(fileName, imageFile);

        if (uploadError) {
          // Si l'erreur est "Bucket not found", c'est que l'utilisateur n'a pas créé le bucket
          if (uploadError.message.includes('not found')) {
            throw new Error("Le dossier 'recipe-images' n'existe pas dans votre Storage Supabase. Veuillez le créer et le mettre en PUBLIC.");
          }
          throw new Error(`Erreur Image: ${uploadError.message}`);
        }

        const { data: publicUrlData } = supabase.storage
          .from('recipe-images')
          .getPublicUrl(fileName);

        imageUrl = publicUrlData.publicUrl;
      }

      // 2. Insertion en base
      const { error: insertError } = await supabase
        .from('recipes')
        .insert({
          title: title.trim(),
          category,
          ingredients: filteredIngredients,
          instructions: filteredInstructions,
          image_url: imageUrl
        });

      if (insertError) {
        // Erreurs communes de base de données
        if (insertError.code === '42P01') {
          throw new Error("La table 'recipes' n'existe pas dans votre base de données. Avez-vous exécuté le script SQL ?");
        }
        if (insertError.code === '42501') {
          throw new Error("Accès refusé (RLS). Vous devez ajouter une Policy 'Enable insert for authenticated users' ou 'Enable for all' sur la table recipes.");
        }
        throw new Error(`Erreur Base de données (${insertError.code}): ${insertError.message}`);
      }

      alert('Recette publiée avec succès !');
      navigate('/');
    } catch (error: any) {
      console.error('Erreur complète:', error);
      alert(error.message || "Une erreur inconnue est survenue.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-white rounded-3xl shadow-xl border border-gray-100 max-w-2xl mx-auto overflow-hidden animate-slideUp">
      <div className="bg-orange-500 p-8 text-white">
        <h1 className="text-3xl font-black">Ajouter une pépite</h1>
        <p className="opacity-90">Remplissez le formulaire ci-dessous.</p>
      </div>

      <form onSubmit={handleSubmit} className="p-8 space-y-8">
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="block text-sm font-bold text-gray-700 uppercase">Nom de la recette</label>
            <input 
              type="text" required value={title} onChange={(e) => setTitle(e.target.value)}
              className="w-full px-4 py-3 rounded-xl bg-gray-50 border border-gray-200 focus:ring-2 focus:ring-orange-500 outline-none"
            />
          </div>
          <div className="space-y-2">
            <label className="block text-sm font-bold text-gray-700 uppercase">Catégorie</label>
            {/* Fixed: category is now a string, so we use it directly and remove the invalid type cast */}
            <select 
              value={category} onChange={(e) => setCategory(e.target.value)}
              className="w-full px-4 py-3 rounded-xl bg-gray-50 border border-gray-200 focus:ring-2 focus:ring-orange-500 outline-none appearance-none"
            >
              <option value="Entrée">Entrée</option>
              <option value="Plat">Plat</option>
              <option value="Dessert">Dessert</option>
            </select>
          </div>
        </div>

        <div className="space-y-2">
          <label className="block text-sm font-bold text-gray-700 uppercase">Photo (Optionnel)</label>
          <div className={`relative h-40 rounded-2xl border-2 border-dashed flex items-center justify-center overflow-hidden ${imagePreview ? 'border-orange-500' : 'border-gray-200'}`}>
            {imagePreview ? (
              <>
                <img src={imagePreview} className="w-full h-full object-cover" />
                <button type="button" onClick={() => {setImageFile(null); setImagePreview(null);}} className="absolute top-2 right-2 bg-red-500 text-white p-2 rounded-full"><i className="fas fa-times"></i></button>
              </>
            ) : (
              <div className="text-center p-4">
                <i className="fas fa-camera text-2xl text-gray-300 mb-1"></i>
                <p className="text-xs text-gray-400">Cliquez pour ajouter</p>
                <input type="file" accept="image/*" className="absolute inset-0 opacity-0 cursor-pointer" onChange={handleImageChange} />
              </div>
            )}
          </div>
        </div>

        <div className="space-y-4">
          <label className="font-bold text-gray-700 uppercase flex justify-between">Ingrédients <button type="button" onClick={() => handleAddField(setIngredients)} className="text-orange-500 text-xs">+ Ajouter</button></label>
          {ingredients.map((ing, idx) => (
            <div key={idx} className="flex space-x-2">
              <input type="text" value={ing} onChange={(e) => handleFieldChange(idx, e.target.value, setIngredients)} className="flex-grow px-4 py-2 rounded-xl bg-gray-50 border border-gray-200" placeholder={`Ingrédient ${idx + 1}`} />
              <button type="button" onClick={() => handleRemoveField(idx, setIngredients, ingredients)} className="text-gray-300 hover:text-red-500"><i className="fas fa-trash"></i></button>
            </div>
          ))}
        </div>

        <div className="space-y-4">
          <label className="font-bold text-gray-700 uppercase flex justify-between">Étapes <button type="button" onClick={() => handleAddField(setInstructions)} className="text-orange-500 text-xs">+ Ajouter</button></label>
          {instructions.map((step, idx) => (
            <div key={idx} className="flex space-x-2">
              <textarea value={step} onChange={(e) => handleFieldChange(idx, e.target.value, setInstructions)} className="flex-grow px-4 py-2 rounded-xl bg-gray-50 border border-gray-200 h-20" placeholder={`Étape ${idx + 1}`} />
              <button type="button" onClick={() => handleRemoveField(idx, setInstructions, instructions)} className="text-gray-300 hover:text-red-500"><i className="fas fa-trash"></i></button>
            </div>
          ))}
        </div>

        <button type="submit" disabled={loading} className={`w-full py-4 rounded-2xl font-black text-lg text-white shadow-lg transition-all ${loading ? 'bg-gray-400' : 'bg-orange-500 hover:bg-orange-600'}`}>
          {loading ? 'Envoi en cours...' : 'Publier ma recette'}
        </button>
      </form>
    </div>
  );
};

export default AddRecipeView;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { supabase } from '../supabaseClient';
import { Recipe, Category } from '../types';

const RecipeDetailView: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [recipe, setRecipe] = useState<Recipe | null>(null);
  const [categoryInfo, setCategoryInfo] = useState<Category | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (id) fetchRecipe(id);
  }, [id]);

  const fetchRecipe = async (recipeId: string) => {
    try {
      setLoading(true);
      const { data, error } = await supabase.from('recipes').select('*').eq('id', recipeId).single();
      if (error) throw error;
      setRecipe(data);

      // Fetch color info
      const { data: catData } = await supabase.from('categories').select('*').eq('name', data.category).single();
      if (catData) setCategoryInfo(catData);
    } catch (error) {
      navigate('/');
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async () => {
    if (!confirm("Voulez-vous vraiment supprimer cette recette ?")) return;
    const { error } = await supabase.from('recipes').delete().eq('id', id);
    if (!error) navigate('/');
    else alert("Erreur lors de la suppression");
  };

  const exportJPG = async () => {
    if (!recipe) return;

    // Dimensions A4 à 96 DPI
    const width = 794; 
    const height = 1123;
    const canvas = document.createElement('canvas');
    canvas.width = width;
    canvas.height = height;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Fond blanc
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, width, height);

    // 1. Bandeau (2cm ≈ 75px)
    const bandHeight = 75;
    const mainColor = categoryInfo?.color || '#f97316';
    ctx.fillStyle = mainColor;
    ctx.fillRect(0, 0, width, bandHeight);

    ctx.fillStyle = '#ffffff';
    ctx.font = 'bold 32px Inter, sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText(recipe.title.toUpperCase(), width / 2, bandHeight / 2 + 10);

    // 2. Photo (5cm ≈ 190px de haut)
    let nextY = bandHeight + 40;
    if (recipe.image_url) {
      const img = new Image();
      img.crossOrigin = "anonymous";
      img.src = recipe.image_url;
      try {
        await new Promise((resolve, reject) => {
          img.onload = resolve;
          img.onerror = reject;
        });

        const displayHeight = 190;
        const ratio = img.width / img.height;
        const displayWidth = displayHeight * ratio;
        const xPos = (width - displayWidth) / 2;

        // Bordure 2px
        ctx.fillStyle = '#000000';
        ctx.fillRect(xPos - 2, nextY - 2, displayWidth + 4, displayHeight + 4);
        ctx.drawImage(img, xPos, nextY, displayWidth, displayHeight);
        nextY += displayHeight + 50;
      } catch (e) {
        console.error("Erreur chargement image pour export:", e);
        nextY += 20;
      }
    }

    // 3. Contenu Colonnes 1/4 - 3/4
    const col1X = 50;
    const col1Width = (width - 100) * 0.25;
    const col2X = col1X + col1Width + 40;
    const col2Width = (width - 100) * 0.75 - 40;

    // Ingrédients
    ctx.textAlign = 'left';
    ctx.fillStyle = '#333333';
    ctx.font = 'bold 18px Inter, sans-serif';
    ctx.fillText('INGRÉDIENTS', col1X, nextY);

    ctx.font = '14px Inter, sans-serif';
    let ingY = nextY + 30;
    recipe.ingredients.forEach(ing => {
      ctx.fillText('• ' + ing, col1X, ingY, col1Width);
      ingY += 22;
    });

    // Instructions
    ctx.font = 'bold 18px Inter, sans-serif';
    ctx.fillText('PRÉPARATION', col2X, nextY);

    ctx.font = '14px Inter, sans-serif';
    let stepY = nextY + 30;
    recipe.instructions.forEach((step, idx) => {
      const text = `Etape ${idx + 1} : ${step}`;
      // Basic line wrapping
      const words = text.split(' ');
      let line = '';
      words.forEach(word => {
        let testLine = line + word + ' ';
        if (ctx.measureText(testLine).width > col2Width) {
          ctx.fillText(line, col2X, stepY);
          line = word + ' ';
          stepY += 20;
        } else {
          line = testLine;
        }
      });
      ctx.fillText(line, col2X, stepY);
      stepY += 35;
    });

    // 4. Ligne séparatrice (2px d'épaisseur)
    const finalContentY = Math.max(ingY, stepY);
    ctx.strokeStyle = mainColor;
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(col1X + col1Width + 20, nextY);
    ctx.lineTo(col1X + col1Width + 20, finalContentY);
    ctx.stroke();

    // Download
    const dataUrl = canvas.toDataURL('image/jpeg', 0.9);
    const link = document.createElement('a');
    link.download = `Recette-${recipe.title}.jpg`;
    link.href = dataUrl;
    link.click();
  };

  if (loading) return <div className="h-64 flex items-center justify-center"><div className="w-12 h-12 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div></div>;
  if (!recipe) return null;

  const categoryColor = categoryInfo?.color || '#f97316';

  return (
    <div className="bg-white rounded-3xl overflow-hidden shadow-xl border border-gray-100 animate-slideUp">
      <div className="relative h-64 sm:h-80">
        <img src={recipe.image_url || `https://picsum.photos/seed/${recipe.id}/800/600`} className="w-full h-full object-cover" />
        <div className="absolute top-4 left-4 flex space-x-2">
          <button onClick={() => navigate(-1)} className="w-10 h-10 bg-white/90 rounded-full flex items-center justify-center shadow-lg"><i className="fas fa-arrow-left"></i></button>
        </div>
        <div className="absolute top-4 right-4 flex space-x-2">
          <button onClick={exportJPG} title="Exporter JPG" className="w-10 h-10 bg-blue-500 text-white rounded-full flex items-center justify-center shadow-lg hover:bg-blue-600"><i className="fas fa-file-image"></i></button>
          <Link to={`/recipe/edit/${recipe.id}`} className="w-10 h-10 bg-orange-500 text-white rounded-full flex items-center justify-center shadow-lg hover:bg-orange-600"><i className="fas fa-edit"></i></Link>
          <button onClick={handleDelete} className="w-10 h-10 bg-red-500 text-white rounded-full flex items-center justify-center shadow-lg hover:bg-red-600"><i className="fas fa-trash"></i></button>
        </div>
      </div>

      <div className="p-8 space-y-8">
        <header className="space-y-2 text-center">
          <span className="px-4 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest text-white shadow-sm" style={{ backgroundColor: categoryColor }}>
            {recipe.category}
          </span>
          <h1 className="text-4xl font-black text-gray-900">{recipe.title}</h1>
        </header>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
          <aside className="space-y-4">
            <h2 className="font-black text-lg border-b-2 pb-2" style={{ borderColor: categoryColor }}>INGRÉDIENTS</h2>
            <ul className="space-y-2">
              {recipe.ingredients.map((ing, i) => (
                <li key={i} className="flex items-center space-x-2 text-gray-700 font-medium">
                  <div className="w-2 h-2 rounded-full" style={{ backgroundColor: categoryColor }}></div>
                  <span>{ing}</span>
                </li>
              ))}
            </ul>
          </aside>

          <section className="md:col-span-2 space-y-4">
            <h2 className="font-black text-lg border-b-2 pb-2" style={{ borderColor: categoryColor }}>PRÉPARATION</h2>
            <div className="space-y-6">
              {recipe.instructions.map((step, i) => (
                <div key={i} className="flex space-x-4">
                  <span className="flex-shrink-0 w-8 h-8 rounded-lg flex items-center justify-center text-white font-bold text-sm" style={{ backgroundColor: categoryColor }}>{i + 1}</span>
                  <p className="text-gray-700 leading-relaxed pt-1">{step}</p>
                </div>
              ))}
            </div>
          </section>
        </div>
      </div>
    </div>
  );
};

export default RecipeDetailView;

