 * SQL À EXÉCUTER DANS LE SQL EDITOR DE SUPABASE :
 * 
 * -- 1. Tables de base
 * CREATE TABLE IF NOT EXISTS categories (
 *   id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
 *   name TEXT UNIQUE NOT NULL,
 *   color TEXT NOT NULL DEFAULT '#f97316',
