        img.onload = () => {
          iframe.contentWindow?.focus();
          iframe.contentWindow?.print();
          // Nettoyage après un délai pour laisser le temps au dialogue de s'ouvrir
          setTimeout(() => {
            document.body.removeChild(iframe);
          }, 1000);
        };
      }
    }
  };

